"use client";

import React from 'react';
import AudioButton from '../audio/AudioButton';
import { PartOfSpeechBadge } from './WordCard';

export interface WordDetailUsage {
    /** The word's own language, e.g. a Mi'kmaq example sentence. */
    example: string;
    /** English (or your reference language) translation of the example. */
    translation: string;
    /** Recordings of this specific example sentence, if any. */
    audio?: { url: string; label: string }[];
}

export interface WordDetailAlternateForm {
    text: string;
    gloss?: string;
    note?: string;
    href?: string;
}

export interface WordDetailData {
    word: string;
    pronunciation?: string;
    partOfSpeech?: string;
    translations?: string[];
    definitions: string[];
    usages?: WordDetailUsage[];
    alternateForms?: WordDetailAlternateForm[];
    /** Citation strings for where this entry's data came from. */
    sources?: string[];
    /** Link to view the entry on its original source site, if any. */
    sourceUrl?: string;
    /** Recordings of the word itself (not an example), by speaker. */
    audio?: { url: string; label: string }[];
}

export interface WordDetailPageProps {
    data: WordDetailData;
    className?: string;
}

const sectionStyle: React.CSSProperties = {
    border: '1.5px solid var(--dui-border, currentColor)',
    borderRadius: 'var(--dui-radius, 0.5rem)',
    overflow: 'hidden',
};
const sectionHeaderStyle: React.CSSProperties = {
    padding: '0.9rem 1.25rem',
    background: 'var(--dui-accent, #a8402c)',
    color: 'var(--dui-accent-foreground, #fff)',
    fontWeight: 800,
    textTransform: 'uppercase',
    letterSpacing: '0.03em',
    fontSize: '0.95rem',
};

/**
 * A full word entry: header (pronunciation, part of speech, audio),
 * translations, numbered definitions, usage examples with their own audio,
 * alternate/inflected forms, and source citations. `WordCard` is the list
 * item; this is the page you land on when you click one.
 */
export default function WordDetailPage({ data, className }: WordDetailPageProps) {
    return (
        <div className={className} style={{ display: 'grid', gap: '2rem', gridTemplateColumns: 'minmax(0, 2fr) minmax(0, 1fr)' }}>
            <div style={{ minWidth: 0 }}>
                <div style={{ borderBottom: '3px solid var(--dui-border, currentColor)', paddingBottom: '1.5rem', marginBottom: '2rem' }}>
                    <h1 style={{ fontSize: 'clamp(2.5rem, 6vw, 4.5rem)', fontWeight: 900, letterSpacing: '-0.02em', margin: '0 0 0.5rem', wordBreak: 'break-word' }}>
                        {data.word}
                    </h1>
                    {data.pronunciation && (
                        <p style={{ fontSize: '1.25rem', fontWeight: 700, opacity: 0.6, margin: '0 0 0.75rem' }}>{data.pronunciation}</p>
                    )}
                    {data.partOfSpeech && (
                        <div style={{ marginBottom: '1rem' }}><PartOfSpeechBadge>{data.partOfSpeech}</PartOfSpeechBadge></div>
                    )}
                    {data.audio && data.audio.length > 0 && (
                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem' }}>
                            {data.audio.map((rec, i) => <AudioButton key={i} url={rec.url} label={rec.label} />)}
                        </div>
                    )}
                </div>

                {data.translations && data.translations.length > 0 && (
                    <div style={{ marginBottom: '2rem' }}>
                        <h2 style={{ fontSize: '0.85rem', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '0.05em', opacity: 0.6, margin: '0 0 0.75rem' }}>
                            Translations
                        </h2>
                        <ul style={{ margin: 0, padding: 0, listStyle: 'none', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                            {data.translations.map((t, i) => (
                                <li key={i} style={{ fontSize: '1.15rem', fontWeight: 700 }}>{t}</li>
                            ))}
                        </ul>
                    </div>
                )}

                {data.definitions.length > 0 && (
                    <div>
                        <h2 style={{ fontSize: '0.85rem', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '0.05em', opacity: 0.6, margin: '0 0 1rem' }}>
                            Definitions
                        </h2>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
                            {data.definitions.map((def, i) => (
                                <div key={i} style={{ display: 'flex', gap: '1rem', alignItems: 'flex-start' }}>
                                    <span style={{
                                        flexShrink: 0, width: '2rem', height: '2rem', borderRadius: '9999px',
                                        background: 'var(--dui-accent, #a8402c)', color: 'var(--dui-accent-foreground, #fff)',
                                        display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 800, fontSize: '0.95rem',
                                    }}>
                                        {i + 1}
                                    </span>
                                    <p style={{ fontSize: '1.2rem', fontWeight: 600, lineHeight: 1.4, margin: '0.15rem 0 0' }}>{def}</p>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem', minWidth: 0 }}>
                {data.usages && data.usages.length > 0 && (
                    <div style={sectionStyle}>
                        <div style={sectionHeaderStyle}>Usage examples</div>
                        <div style={{ padding: '1.25rem', display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
                            {data.usages.map((usage, i) => (
                                <div key={i} style={{ borderLeft: '3px solid var(--dui-accent, #a8402c)', paddingLeft: '0.9rem' }}>
                                    <p style={{ fontWeight: 700, margin: '0 0 0.3rem' }}>{usage.example}</p>
                                    <p style={{ fontStyle: 'italic', opacity: 0.7, margin: usage.audio?.length ? '0 0 0.5rem' : 0 }}>{usage.translation}</p>
                                    {usage.audio && usage.audio.length > 0 && (
                                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.4rem' }}>
                                            {usage.audio.map((rec, j) => <AudioButton key={j} url={rec.url} label={rec.label} />)}
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {data.alternateForms && data.alternateForms.length > 0 && (
                    <div style={sectionStyle}>
                        <div style={{ ...sectionHeaderStyle, background: 'var(--dui-fg, #000)', color: 'var(--dui-bg, #fff)' }}>Other forms</div>
                        <ul style={{ margin: 0, padding: '1.25rem', listStyle: 'none', display: 'flex', flexDirection: 'column', gap: '0.6rem' }}>
                            {data.alternateForms.map((form, i) => {
                                const content = (
                                    <>
                                        <strong>{form.text}</strong>
                                        {form.gloss && <span style={{ opacity: 0.6 }}> — {form.gloss}</span>}
                                        {form.note && <span style={{ opacity: 0.5, fontSize: '0.85em' }}> {form.note}</span>}
                                    </>
                                );
                                return (
                                    <li key={i} style={{ fontSize: '0.95rem', lineHeight: 1.4 }}>
                                        {form.href ? <a href={form.href} style={{ color: 'inherit' }}>{content}</a> : content}
                                    </li>
                                );
                            })}
                        </ul>
                    </div>
                )}

                {data.sources && data.sources.length > 0 && (
                    <div style={{ ...sectionStyle, borderStyle: 'dashed' }}>
                        <div style={{ padding: '1.25rem' }}>
                            <h3 style={{ fontSize: '0.75rem', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '0.05em', opacity: 0.6, margin: '0 0 0.75rem' }}>
                                Sources
                            </h3>
                            <ul style={{ margin: 0, padding: 0, listStyle: 'none', display: 'flex', flexDirection: 'column', gap: '0.4rem' }}>
                                {data.sources.map((src, i) => (
                                    <li key={i} style={{ fontSize: '0.85rem', opacity: 0.7, lineHeight: 1.4 }}>{src}</li>
                                ))}
                            </ul>
                            {data.sourceUrl && (
                                <a href={data.sourceUrl} target="_blank" rel="noopener noreferrer" style={{ display: 'inline-block', marginTop: '0.9rem', fontSize: '0.85rem', fontWeight: 700, textDecoration: 'underline', color: 'inherit' }}>
                                    View original entry →
                                </a>
                            )}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import React from 'react';
import type { DictionaryWord } from './types';

export interface WordCardProps {
    word: DictionaryWord;
    className?: string;
}

/** A small pill badge — used internally for part-of-speech, exported in case you want it standalone. */
export function PartOfSpeechBadge({ children }: { children: React.ReactNode }) {
    return (
        <span
            style={{
                display: 'inline-block',
                padding: '0.2rem 0.6rem',
                fontSize: '0.65rem',
                fontWeight: 700,
                textTransform: 'uppercase',
                letterSpacing: '0.05em',
                borderRadius: 'var(--dui-radius, 9999px)',
                background: 'var(--dui-muted, rgba(127,127,127,0.15))',
                color: 'var(--dui-fg, currentColor)',
            }}
        >
            {children}
        </span>
    );
}

/** A word list card: word, pronunciation, part-of-speech badge, first definition.
 *  Renders as a plain `<a>` when `word.href` is set, a `<div>` otherwise. */
export default function WordCard({ word, className }: WordCardProps) {
    const Tag = word.href ? 'a' : 'div';
    return (
        <Tag
            href={word.href}
            className={className}
            style={{
                display: 'block',
                padding: '1.25rem',
                borderRadius: 'var(--dui-radius, 0.75rem)',
                border: '1px solid var(--dui-border, rgba(127,127,127,0.25))',
                textDecoration: 'none',
                color: 'inherit',
            }}
        >
            <div style={{ display: 'flex', alignItems: 'baseline', justifyContent: 'space-between', gap: '0.75rem', marginBottom: '0.35rem' }}>
                <h3 style={{ fontSize: '1.25rem', fontWeight: 800, margin: 0 }}>{word.word}</h3>
                {word.partOfSpeech && <PartOfSpeechBadge>{word.partOfSpeech}</PartOfSpeechBadge>}
            </div>
            {word.pronunciation && (
                <p style={{ fontSize: '0.85rem', opacity: 0.6, margin: '0 0 0.4rem' }}>{word.pronunciation}</p>
            )}
            {word.definitions[0] && (
                <p style={{ fontSize: '0.95rem', margin: 0, opacity: 0.9 }}>{word.definitions[0]}</p>
            )}
        </Tag>
    );
}

"use client";

import React, { useEffect, useRef, useState } from 'react';
import { Volume2, Square } from 'lucide-react';
import { playRecording, stopAudio } from './play-audio';
import { cn } from '../utils';

export interface AudioButtonProps {
    /** Playable audio URL (mp3, wav, etc.) — fetch it from wherever your data lives. */
    url: string;
    /** Visible label, e.g. a speaker name or "play". */
    label: string;
    className?: string;
    style?: React.CSSProperties;
}

/**
 * A play/stop button for one audio recording. Playing this button stops
 * any other `<AudioButton>` (or `playRecording()` call) currently playing,
 * so multiple buttons on a page never overlap.
 *
 * Ships with sane default styling via CSS custom properties (`--dui-*`) so
 * it looks reasonable with zero setup; override with `className`/`style`,
 * or redeclare the `--dui-*` variables to theme it, in either the installed
 * package or a copy-pasted version.
 */
export default function AudioButton({ url, label, className, style }: AudioButtonProps) {
    const audioRef = useRef<HTMLAudioElement | null>(null);
    const [playing, setPlaying] = useState(false);

    useEffect(() => {
        const onOtherPlay = () => setPlaying(false);
        window.addEventListener('dictionary-ui-audio-play', onOtherPlay);
        return () => {
            window.removeEventListener('dictionary-ui-audio-play', onOtherPlay);
            audioRef.current?.pause();
        };
    }, []);

    const toggle = async () => {
        if (playing) {
            stopAudio();
            setPlaying(false);
            return;
        }
        try {
            const audio = await playRecording(url);
            audioRef.current = audio;
            setPlaying(true);
            audio.addEventListener('ended', () => setPlaying(false));
            audio.addEventListener('error', () => setPlaying(false));
        } catch {
            setPlaying(false);
        }
    };

    return (
        <button
            type="button"
            onClick={toggle}
            aria-pressed={playing}
            className={cn('dui-audio-button', playing && 'dui-audio-button--playing', className)}
            style={{
                display: 'inline-flex',
                alignItems: 'center',
                gap: '0.5rem',
                padding: '0.375rem 0.875rem',
                borderRadius: 'var(--dui-radius, 9999px)',
                border: '1.5px solid var(--dui-border, currentColor)',
                background: playing ? 'var(--dui-accent, #a8402c)' : 'var(--dui-bg, transparent)',
                color: playing ? 'var(--dui-accent-foreground, #fff)' : 'var(--dui-fg, currentColor)',
                fontWeight: 700,
                fontSize: '0.75rem',
                textTransform: 'uppercase',
                letterSpacing: '0.04em',
                cursor: 'pointer',
                transition: 'background 0.15s ease, color 0.15s ease',
                ...style,
            }}
        >
            {playing ? <Square size={14} /> : <Volume2 size={14} />}
            {label}
        </button>
    );
}

"use client";

/**
 * Shared audio playback for recordings.
 *
 * Two problems this solves:
 *  - On some systems (notably Linux/PipeWire) the audio output device is
 *    suspended until the first sound, clipping the start of the first clip.
 *    A short burst of silence on the first user interaction wakes it up.
 *  - `new Audio(url).play()` without a kept reference can be garbage-collected
 *    mid-playback; the module holds the current element.
 *
 * Framework-agnostic — takes only a playable URL, no project-specific data
 * shape (manifest format, API routes, etc.) baked in.
 */

const STOP_EVENT = 'dictionary-ui-audio-play';

// 0.3s of silence as a tiny WAV data URI (44-byte header + zeroed samples).
const SILENCE = (() => {
    const rate = 8000;
    const seconds = 0.3;
    const samples = Math.floor(rate * seconds);
    const buf = new ArrayBuffer(44 + samples * 2);
    const v = new DataView(buf);
    const str = (o: number, s: string) => {
        for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i));
    };
    str(0, 'RIFF'); v.setUint32(4, 36 + samples * 2, true); str(8, 'WAVE');
    str(12, 'fmt '); v.setUint32(16, 16, true); v.setUint16(20, 1, true); v.setUint16(22, 1, true);
    v.setUint32(24, rate, true); v.setUint32(28, rate * 2, true); v.setUint16(32, 2, true); v.setUint16(34, 16, true);
    str(36, 'data'); v.setUint32(40, samples * 2, true);
    let b = '';
    new Uint8Array(buf).forEach((byte) => { b += String.fromCharCode(byte); });
    return 'data:audio/wav;base64,' + btoa(b);
})();

let warmed = false;
let current: HTMLAudioElement | null = null;

async function warmUp() {
    if (warmed) return;
    warmed = true;
    try {
        const s = new Audio(SILENCE);
        s.volume = 1; // real (silent) samples must reach the sink to resume it
        await s.play();
        await new Promise((r) => setTimeout(r, 250));
    } catch {
        /* autoplay rejection etc. — playback below still works */
    }
}

/** Stop whatever is playing (also fired by other players via the stop event). */
export function stopAudio() {
    current?.pause();
    current = null;
}

if (typeof window !== 'undefined') {
    window.addEventListener(STOP_EVENT, () => {
        current?.pause();
        current = null;
    });
}

/**
 * Play a recording. Returns the HTMLAudioElement so callers can track
 * ended/error state. Any other playing recording is stopped first.
 */
export async function playRecording(url: string): Promise<HTMLAudioElement> {
    window.dispatchEvent(new CustomEvent(STOP_EVENT));
    await warmUp();
    const audio = new Audio(url);
    audio.preload = 'auto';
    current = audio;
    const clear = () => { if (current === audio) current = null; };
    audio.addEventListener('ended', clear);
    audio.addEventListener('error', clear);
    await audio.play();
    return audio;
}

/** Joins truthy class names. No Tailwind-merge semantics — kept dependency-free
 *  so this package doesn't force a specific styling toolchain on consumers. */
export function cn(...classes: Array<string | false | null | undefined>): string {
    return classes.filter(Boolean).join(' ');
}
